using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---

// Web defaults include a reflection-based resolver, so every public type is resolvable.
var webOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = webOptions.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person>  -> Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 38), personInfo);
Console.WriteLine($"Serialized           -> {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// With the same web options every type resolves, so this succeeds:
if (webOptions.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded -> {found!.Type.Name}");
}

// Now create options whose resolver only knows about a custom context
// that does NOT include UnknownWidget.
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = PersonOnlyContext.Default
};

if (restrictedOptions.TryGetTypeInfo<UnknownWidget>(out JsonTypeInfo<UnknownWidget>? widgetInfo))
{
    Console.WriteLine($"TryGetTypeInfo<UnknownWidget> succeeded -> {widgetInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<UnknownWidget> returned false — no metadata available");
}

// --- types ---

public record Person(string Name, int Age);

public class UnknownWidget { public int Id { get; set; } }

// A source-generated context that only knows about Person.
[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;

